var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그 기계야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきたあのマシンだからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this machine, that you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，它是必不可少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그 기계와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まであのマシンとともにいることを。","ENG":"that you'll be with it, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和它一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called it to your office. It said it'd be here soon.","TWN":"做好心理準備後，你將它傳喚到老闆辦公室，它說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"TITAN_FAW_HYERION_NULL","text":{"KOREA":"내가 필요한 일이 있나, 사장?","JPN":"社長、吾輩の力が必要な仕事でもあるのか？","ENG":"You needed me for something, Boss?","TWN":"老闆，有什麼需要我出力的嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_HYERION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TITAN_FAW_HYERION_NULL","text":{"KOREA":"뭐든지 말하도록! 헬리오스 시스템이 있다면 어디든지…….","JPN":"何でも言ってくれ！　ヘリオスシステムがあればどこでも……","ENG":"Just say the word! With the Helios System, I can fly anywhere–","TWN":"儘管說吧！有了雷射系統，哪裡都能去……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_HYERION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"TITAN_FAW_HYERION_NULL","text":{"KOREA":"음? 이건 종신계약……?","JPN":"む？　これは終身契約……？","ENG":"Mm? A lifetime contract...?","TWN":"嗯？這是終身契約……？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_HYERION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"TITAN_FAW_HYERION_NULL","text":{"KOREA":"사장, 체르노프 박사를 알고 있나?","JPN":"社長、チェルノフ博士を知っているか？","ENG":"Boss, do you know Dr. Chernov?","TWN":"老闆，你知道切爾諾夫博士嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_HYERION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"TITAN_FAW_HYERION_NULL","text":{"KOREA":"나라는 인공지능을 탄생시킨 사람은 엠버 소장이지만…….","JPN":"吾輩という人工知能を作り出したのはアンバー所長であるが……","ENG":"Director Ember may have been the one who created my AI core...","TWN":"雖然讓我這個人工智慧誕生的人是琥珀所長……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_HYERION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TITAN_FAW_HYERION_NULL","text":{"KOREA":"나에게 영혼이 있다는 것을 알려준 사람은 체르노프 박사라네.","JPN":"吾輩に魂があるということを教えてくれたのは、チェルノフ博士だ。","ENG":"But it was Dr. Chernov who taught me that I possess a soul.","TWN":"但讓我明白自己擁有靈魂的人，是切爾諾夫博士。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_HYERION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"TITAN_FAW_HYERION_NULL","text":{"KOREA":"그 사람 덕분에, 나는 이렇게 사장 곁에서 사람들을 지킬 수 있게 되었지!","JPN":"彼のおかげで、吾輩はこうやって社長のそばで人々を守ることができるようになった！","ENG":"Because of him, I can stand here today, guarding people by your side!","TWN":"多虧了他，我才能在老闆身旁守護人們！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_HYERION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"TITAN_FAW_HYERION_NULL","text":{"KOREA":"그리고 시간이 흘러 지금.","JPN":"あの時から月日が経った現在。","ENG":"Even now, after all this time.","TWN":"之後時光流逝，直到如今。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_HYERION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"TITAN_FAW_HYERION_NULL","text":{"KOREA":"체르노프 박사의, 아니, 퓨처 앳 워의 사람을 지키고자 하는 의지가 이어져……","JPN":"チェルノフ博士の……いや、フューチャーアットウォーの「人を守ろうとする意志」は受け継がれ……","ENG":"His will– No, the will of Future-at-War, to protect mankind, has been carried forward...","TWN":"切爾諾夫博士，不，應該說是天啟兵器那個想守護人們的意志延續了下來……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_HYERION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"TITAN_FAW_HYERION_NULL","text":{"KOREA":"마침내 히페리온 플랜을 완성할 수 있었지.","JPN":"ついにハイペリオンプランは完成したのだ。","ENG":"And at last, the Hyperion Plan has been completed.","TWN":"最終才得以完成海柏利昂計畫。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_HYERION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"TITAN_FAW_HYERION_NULL","text":{"KOREA":"내 아다만트 합금에 맹세하건대, 사장과 함께 싸워온 모든 순간이 보람찼네!","JPN":"社長と共に戦ったすべての瞬間は充実していた。吾輩のアダマント合金に誓おう！","ENG":"I swear upon my adamant alloy that every moment fighting at your side has been worth it!","TWN":"我以我的亞達曼合金發誓，與老闆並肩作戰的每一刻都充滿價值！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_HYERION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TITAN_FAW_HYERION_NULL","text":{"KOREA":"사람들을 지키고, 세계를 지키기 위해 싸우는 모든 것들이……","JPN":"人々を守り、世界を守るために戦うすべてが……","ENG":"Every act to protect people and to defend this world...","TWN":"為了守護人們、守護世界而戰的一切……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_HYERION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TITAN_FAW_HYERION_NULL","text":{"KOREA":"내가 이 세상에 태어난 이유를 명확히 해주고 있으니 말이야!","JPN":"吾輩がこの世に生み出された理由を揺るぎないものにしてくれている！","ENG":"It all affirms the very reason I was brought into existence!","TWN":"正明確地讓我明白，我誕生於這個世界的理由！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_HYERION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"TITAN_FAW_HYERION_NULL","text":{"KOREA":"사장은 세계를 지키기 위해 싸우고 있다고 했나?","JPN":"社長は世界を守るために戦うと言っていただろう。","ENG":"You said you were fighting to protect the world, didn't you, Boss?","TWN":"老闆，你說過你正為了守護世界而戰嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_HYERION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"TITAN_FAW_HYERION_NULL","text":{"KOREA":"나 역시 인류를 수호하기 위해 제조되었지.","JPN":"吾輩もまた、人類を守護するために製造された。","ENG":"I too was created to protect mankind.","TWN":"我也同樣是為了守護人類而被製造出來的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_HYERION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"TITAN_FAW_HYERION_NULL","text":{"KOREA":"내 인공지능은 자아가 형성된 이래로 단 한 번도 제조 목적을 의심해 본 적이 없네!","JPN":"吾輩の人工知能は自我が形成されて以来、たった一度も己の製造目的を疑ったことがない！","ENG":"And ever since my AI gained self-awareness, I have never once doubted that purpose!","TWN":"我的人工智慧自形成自我以來，從未懷疑過自己的製造目的！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_HYERION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"TITAN_FAW_HYERION_NULL","text":{"KOREA":"그러니, 사장.","JPN":"だから社長。","ENG":"So, Boss.","TWN":"所以說，老闆。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_HYERION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"TITAN_FAW_HYERION_NULL","text":{"KOREA":"나는 사장의 목표가 반드시 이루어질 것임을 의심하지 않는다네!","JPN":"吾輩は社長の目標が必ず叶うと、信じて疑わないのだ！","ENG":"I have no doubt your goal will be achieved!","TWN":"我堅信老闆的目標一定會實現！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_HYERION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"TITAN_FAW_HYERION_NULL","text":{"KOREA":"하지만… 방수도 안 되는 종이와 도장 따위로 계약하는 건 매우 비효율적이군.","JPN":"しかし……防水もできない紙と印鑑などで契約するとは、非常に非効率的だな。","ENG":"But... sealing a contract with flimsy paper and ink that aren't even waterproof feels terribly inefficient.","TWN":"不過……用那種不防水的紙和印章來簽約，實在太沒效率了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_HYERION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"TITAN_FAW_HYERION_NULL","text":{"KOREA":"아무렴 어떠냐고?","JPN":"別にいいじゃないか、と？","ENG":"It doesn't matter, you say?","TWN":"你是說，那又怎麼樣嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_HYERION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"TITAN_FAW_HYERION_NULL","text":{"KOREA":"하하! 맞는 말일세!","JPN":"ガハハ！　そのとおりだ！","ENG":"Haha! I guess you're right!","TWN":"哈哈！說得也是！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_HYERION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"TITAN_FAW_HYERION_NULL","text":{"KOREA":"중요한 것은 사장과 나 사이의 굳건한 믿음 아니겠는가?","JPN":"大事なのは社長と吾輩の間の確固たる信頼だからな！","ENG":"What truly matters is the unbreakable trust between you and me!","TWN":"重要的是我與老闆之間的堅定信任，不是嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_HYERION_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};